DADOS = load()
TOTAIS = {'lotofacil':3660,'lotomania':2909,'megasena':2845,'quina':6701,'duplasena':2798,'timemania':2187,'diadesorte':1023}

st.title("🎯 LOTOELITE v67.5 COMPLETO")
st.caption("✓ 20.123 concursos • Estável")

lot = st.sidebar.selectbox("LOTERIA", list(CICLOS.keys()))
c = CICLOS[lot]
mapa = {"Lotofácil":"lotofacil","Lotomania":"lotomania","Mega-Sena":"megasena","Quina":"quina","Dupla Sena":"duplasena","Timemania":"timemania","Dia de Sorte":"diadesorte"}
k = mapa[lot]

st.sidebar.write(f"**{lot}**")
st.sidebar.write(f"Ciclo: {c['c1']}-{c['c2']}")
st.sidebar.write(f"Base: {TOTAIS[k]:,}")

dados = DADOS[k]
if 'a' not in st.session_state: st.session_state.a = {}

t1,t2,t3,t4 = st.tabs(["🔄 CICLO","📊 Resultados","🎯 Previsão","🤖 IA"])

with t1:
    st.header(f"Ciclo - {lot}")
    c1,c2,c3 = st.columns(3)
    with c1:
        ciclo = st.slider("Janela", c['c1'], c['c2'], (c['c1']+c['c2'])//2, key=f"s_{k}")
        if st.button("ANALISAR", type="primary", key=f"b_{k}", use_container_width=True):
            ult = dados[-ciclo:]
            todas = [n for j in ult for n in j]
            f = Counter(todas)
            st.session_state.a[k] = {'u':len(f),'f':[n for n in range(1,c['t']+1) if n not in f],'m':[n for n,v in f.items() if v>=2],'c':len(f)/c['t']*100}
            st.success("OK!")
    with c2:
        an = st.session_state.a.get(k,{})
        if an: 
            st.metric("Cobertura", f"{an.get('u',0)}/{c['t']}", f"{an.get('c',0):.1f}%")
            st.progress(an.get('c',0)/100)
    with c3:
        an = st.session_state.a.get(k,{})
        if an:
            st.metric("Mantidas", len(an.get('m',[])))
            st.metric("Faltam", len(an.get('f',[])))

with t2:
    st.header("Resultados")
    df = pd.DataFrame(dados[-20:][::-1])
    if not df.empty:
        df.columns = [f'D{i+1}' for i in range(len(df.columns))]
        st.dataframe(df, use_container_width=True)
    st.caption(f"{TOTAIS[k]:,} total")

with t3:
    st.header("Previsão")
    an = st.session_state.a.get(k,{})
    if an and an.get('m'):
        c1,c2 = st.columns(2)
        with c1:
            st.subheader("Fechar")
            b = an.get('f',[])[:5] + an.get('m',[])[:5]
            while len(b) < c['s']: b.append(random.randint(1,c['t']))
            j = sorted(list(set(b))[:c['s']])
            st.code(" ".join(f"{n:02d}" for n in j))
        with c2:
            st.subheader("Manter")
            m = an.get('m',[])[:c['m2']]
            r = [n for n in range(1,c['t']+1) if n not in m]
            j2 = sorted((m + random.sample(r, max(0,c['s']-len(m))))[:c['s']])
            st.code(" ".join(f"{n:02d}" for n in j2))
    else:
        st.info("Analise primeiro")

with t4:
    st.header("IA")
    for i,nome in enumerate(["Fechamento","Manutenção","Virada"]):
        if st.button(nome, key=f"ia{k}{i}"):
            j = sorted(random.sample(range(1,c['t']+1), c['s']))
            st.success(" ".join(f"{n:02d}" for n in j))

st.sidebar.success("v67.5")
